import React from 'react'
import { Col, Container, Row } from 'react-bootstrap';
import { useTypewriter, Cursor } from "react-simple-typewriter";
import headerImg from "../assets/img/U.jpg";


function Content() {
    const eff =()=>{
        if(typeEffect==='App Developer'){
           let header=document.getElementById('head');
           header.innerText=("I'm Alankrit Gupta an ");
        }
    }
    const [typeEffect] = useTypewriter({
        words: ["Web Developer", "App Developer", "Berozgar"],
        loop: {},
        typeSpeed: 100,
        deleteSpeed: 60,
        onType: {eff}
    })


    return (
        <section className='banner' id='home'>
            <Container>
                <Row className='allign-items-center'>
                    <Col>
                        <div className='whatRu'>
                            <h2>Welcome to my Portfolio, </h2>
                            <h1 id='head'>I'm Alankrit Gupta a <span className='typeEff'>{typeEffect}</span></h1>
                            <p>Lorem ipsum dolor, sit amet consectetur adipisicing elit. Ullam, expedita. Laboriosam inventore facere repudiandae soluta! Dicta animi sint beatae, unde voluptate voluptatem sit, distinctio, magnam est quasi officia optio explicabo?</p>
                        </div>
                    </Col>
                    <Col>
                        <div className='pic'>
                            <img src={headerImg} alt=''></img>
                        </div>
                    </Col>
                </Row>
            </Container>
        </section>
    )
} 

export default Content
